	"net/http"

	"socialpredict/handlers"
	"socialpredict/handlers/bets/dto"
	bets "socialpredict/internal/domain/bets"
	dmarkets "socialpredict/internal/domain/markets"
	dusers "socialpredict/internal/domain/users"
	authsvc "socialpredict/internal/service/auth"
)

const (
	reasonSellValidationFailed handlers.FailureReason = "SELL_VALIDATION_FAILED"
	reasonSellMarketClosed     handlers.FailureReason = "MARKET_CLOSED"
	reasonNoPosition           handlers.FailureReason = "NO_POSITION"
	reasonInsufficientShares   handlers.FailureReason = "INSUFFICIENT_SHARES"
	reasonDustCapExceeded      handlers.FailureReason = "DUST_CAP_EXCEEDED"
	reasonSellMarketNotFound   handlers.FailureReason = "MARKET_NOT_FOUND"
)

// SellPositionHandler returns an HTTP handler that delegates sales to the bets service.
func SellPositionHandler(betsSvc bets.ServiceInterface, usersSvc dusers.ServiceInterface) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			_ = handlers.WriteFailure(w, http.StatusMethodNotAllowed, handlers.ReasonMethodNotAllowed)
			return
		}

		user, httpErr := authsvc.ValidateUserAndEnforcePasswordChangeGetUser(r, usersSvc)
		if httpErr != nil {
			_ = handlers.WriteFailure(w, httpErr.StatusCode, reasonFromAuthError(httpErr))
			return
		}

		req, decodeErr := decodeSellRequest(r)
		if decodeErr != nil {
			_ = handlers.WriteFailure(w, http.StatusBadRequest, handlers.ReasonInvalidRequest)
			return
		}

		result, err := betsSvc.Sell(r.Context(), toSellRequest(req, user.Username))
		if err != nil {
			handleSellError(w, err)
			return
		}

		writeSellResponse(w, result)
	}
}

func decodeSellRequest(r *http.Request) (dto.SellBetRequest, error) {
	var req dto.SellBetRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		return dto.SellBetRequest{}, errors.New("Invalid request body")
	}
	return req, nil
}

func toSellRequest(req dto.SellBetRequest, username string) bets.SellRequest {
	return bets.SellRequest{
		Username: username,
		MarketID: req.MarketID,
		Amount:   req.Amount,
		Outcome:  req.Outcome,
	}
}

func handleSellError(w http.ResponseWriter, err error) {
	if _, ok := err.(bets.ErrDustCapExceeded); ok {
		_ = handlers.WriteFailure(w, http.StatusUnprocessableEntity, reasonDustCapExceeded)
		return
	}

	switch {
	case errors.Is(err, bets.ErrInvalidOutcome), errors.Is(err, bets.ErrInvalidAmount):
		_ = handlers.WriteFailure(w, http.StatusBadRequest, reasonSellValidationFailed)
	case errors.Is(err, bets.ErrMarketClosed):
		_ = handlers.WriteFailure(w, http.StatusConflict, reasonSellMarketClosed)
	case errors.Is(err, bets.ErrNoPosition), errors.Is(err, bets.ErrInsufficientShares):
		reason := reasonNoPosition
		if errors.Is(err, bets.ErrInsufficientShares) {
			reason = reasonInsufficientShares
		}
		_ = handlers.WriteFailure(w, http.StatusUnprocessableEntity, reason)
	case errors.Is(err, dmarkets.ErrMarketNotFound):
		_ = handlers.WriteFailure(w, http.StatusNotFound, reasonSellMarketNotFound)
	default:
		_ = handlers.WriteFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
	}
}

func writeSellResponse(w http.ResponseWriter, result *bets.SellResult) {
	response := dto.SellBetResponse{
		Username:      result.Username,
		MarketID:      result.MarketID,
		SharesSold:    result.SharesSold,
		SaleValue:     result.SaleValue,
		Dust:          result.Dust,
		Outcome:       result.Outcome,
		TransactionAt: result.TransactionAt,
	}

	_ = handlers.WriteResult(w, http.StatusCreated, response)
}

func reasonFromAuthError(err *authsvc.HTTPError) handlers.FailureReason {
	if err == nil {
		return handlers.ReasonInternalError
	}

	switch err.Message {
	case "Authorization header is required", "Invalid token":
		return handlers.ReasonInvalidToken
	case "Password change required":
		return handlers.ReasonPasswordChangeRequired
	case "User not found":
		return handlers.ReasonUserNotFound
	default:
		if err.StatusCode >= http.StatusInternalServerError {
			return handlers.ReasonInternalError
		}
		return handlers.ReasonInvalidToken
	}
}

package usershandlers

import (
	"errors"
	"net/http"
	"strings"

	"socialpredict/handlers"
	"socialpredict/handlers/users/dto"
	dusers "socialpredict/internal/domain/users"
	authsvc "socialpredict/internal/service/auth"
)

func writeProfileError(w http.ResponseWriter, err error, field string) {
	switch {
	case errors.Is(err, dusers.ErrUserNotFound):
		_ = handlers.WriteFailure(w, http.StatusNotFound, handlers.ReasonUserNotFound)
	case errors.Is(err, dusers.ErrInvalidUserData):
		_ = handlers.WriteFailure(w, http.StatusBadRequest, "INVALID_USER_DATA")
	case errors.Is(err, dusers.ErrInvalidCredentials):
		_ = handlers.WriteFailure(w, http.StatusUnauthorized, "INVALID_CREDENTIALS")
	default:
		message := err.Error()
		if isValidationError(message) {
			_ = handlers.WriteFailure(w, http.StatusBadRequest, handlers.ReasonValidationFailed)
			return
		}
		_ = handlers.WriteFailure(w, http.StatusInternalServerError, profileFailureReason(field))
	}
}

func writeProfileJSONError(w http.ResponseWriter, statusCode int, message string) {
	_ = handlers.WriteFailure(w, statusCode, handlers.FailureReason(message))
}

func isValidationError(message string) bool {
	lower := strings.ToLower(message)
	return strings.Contains(lower, "invalid") ||
		strings.Contains(lower, "exceeds") ||
		strings.Contains(lower, "must") ||
		strings.Contains(lower, "cannot") ||
		strings.Contains(lower, "required")
}

func toPrivateUserResponse(user *dusers.User) dto.PrivateUserResponse {
	if user == nil {
		return dto.PrivateUserResponse{}
	}

	return dto.PrivateUserResponse{
		ID:                    user.ID,
		Username:              user.Username,
		DisplayName:           user.DisplayName,
		UserType:              user.UserType,
		InitialAccountBalance: user.InitialAccountBalance,
		AccountBalance:        user.AccountBalance,
		PersonalEmoji:         user.PersonalEmoji,
		Description:           user.Description,
		PersonalLink1:         user.PersonalLink1,
		PersonalLink2:         user.PersonalLink2,
		PersonalLink3:         user.PersonalLink3,
		PersonalLink4:         user.PersonalLink4,
		Email:                 user.Email,
		APIKey:                user.APIKey,
		MustChangePassword:    user.MustChangePassword,
	}
}

func profileFailureReason(field string) handlers.FailureReason {
	switch field {
	case "display name":
		return "DISPLAY_NAME_UPDATE_FAILED"
	case "description":
		return "DESCRIPTION_UPDATE_FAILED"
	case "emoji":
		return "EMOJI_UPDATE_FAILED"
	case "personal links":
		return "PERSONAL_LINKS_UPDATE_FAILED"
	default:
		return handlers.ReasonInternalError
	}
}

func profileAuthFailureReason(err *authsvc.HTTPError) handlers.FailureReason {
	if err == nil {
		return handlers.ReasonInternalError
	}

	switch err.Message {
	case "Authorization header is required", "Invalid token":
		return handlers.ReasonInvalidToken
	case "Password change required":
		return handlers.ReasonPasswordChangeRequired
	case "User not found":
		return handlers.ReasonUserNotFound
	default:
		if err.StatusCode >= http.StatusInternalServerError {
			return handlers.ReasonInternalError
		}
		return handlers.ReasonInvalidToken
	}
}

package auth

import (
	"net/http"
	"strings"

	dusers "socialpredict/internal/domain/users"
)

// Authenticator exposes the authentication operations used by HTTP handlers.
type Authenticator interface {
	CurrentUser(r *http.Request) (*dusers.User, *HTTPError)
	RequireUser(r *http.Request) (*dusers.User, *HTTPError)
	RequireAdmin(r *http.Request) (*dusers.User, *HTTPError)
}

// AuthService provides a façade over the authentication helpers so callers can
// depend on a single injected object rather than package-level functions.
type AuthService struct {
	users dusers.ServiceInterface
}

// NewAuthService constructs a façade that uses the provided users service for
// token validation and password-change enforcement.
func NewAuthService(users dusers.ServiceInterface) *AuthService {
	return &AuthService{users: users}
}

// CurrentUser returns the authenticated user, ensuring any password-change
// requirements are enforced.
func (a *AuthService) CurrentUser(r *http.Request) (*dusers.User, *HTTPError) {
	return ValidateUserAndEnforcePasswordChangeGetUser(r, a.users)
}

// RequireUser resolves the authenticated user without checking the
// must-change-password flag.
func (a *AuthService) RequireUser(r *http.Request) (*dusers.User, *HTTPError) {
	return ValidateTokenAndGetUser(r, a.users)
}

// RequireAdmin ensures the current user is authenticated and has admin privileges.
func (a *AuthService) RequireAdmin(r *http.Request) (*dusers.User, *HTTPError) {
	user, err := a.RequireUser(r)
	if err != nil {
		return nil, err
	}

	if strings.ToUpper(user.UserType) != "ADMIN" {
		return nil, &HTTPError{
			StatusCode: http.StatusForbidden,
			Message:    "admin privileges required",
		}
	}

	return user, nil
}

